import{_ as s,o as e,c as n,ae as i}from"./chunks/framework.BalxkeZv.js";const h=JSON.parse('{"title":"插件体系","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/overview.md","filePath":"plugins/overview.md","lastUpdated":1777140393000}'),l={name:"plugins/overview.md"};function o(p,a,c,t,d,r){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="插件体系" tabindex="-1">插件体系 <a class="header-anchor" href="#插件体系" aria-label="Permalink to &quot;插件体系&quot;">​</a></h1><p>SubForge 插件遵循统一 <code>plugin.json + schema.json</code> 规范。</p><h2 id="插件类型" tabindex="-1">插件类型 <a class="header-anchor" href="#插件类型" aria-label="Permalink to &quot;插件类型&quot;">​</a></h2><ul><li><code>static</code>：直接拉取配置 URL</li><li><code>script</code>：通过登录/刷新/抓取脚本获取配置数据 <ul><li>支持 <code>fetch.subscription.url</code> 二次拉取，默认精简请求头；也支持脚本自定义 <code>headers/user_agent</code></li></ul></li></ul><h2 id="通用必填字段-plugin-json" tabindex="-1">通用必填字段（plugin.json） <a class="header-anchor" href="#通用必填字段-plugin-json" aria-label="Permalink to &quot;通用必填字段（plugin.json）&quot;">​</a></h2><ul><li><code>plugin_id</code></li><li><code>spec_version</code>（当前仅支持 <code>1.x</code>）</li><li><code>name</code></li><li><code>version</code></li><li><code>type</code></li><li><code>config_schema</code></li></ul><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>static 插件：</span></span>
<span class="line"><span>my-plugin/</span></span>
<span class="line"><span>  plugin.json</span></span>
<span class="line"><span>  schema.json</span></span>
<span class="line"><span></span></span>
<span class="line"><span>script 插件：</span></span>
<span class="line"><span>my-plugin/</span></span>
<span class="line"><span>  plugin.json</span></span>
<span class="line"><span>  schema.json</span></span>
<span class="line"><span>  scripts/</span></span>
<span class="line"><span>    fetch.lua</span></span>
<span class="line"><span>    login.lua (可选)</span></span>
<span class="line"><span>    refresh.lua (可选)</span></span></code></pre></div><p>script 插件还要求 <code>entrypoints.fetch</code> 非空。</p><h2 id="导入打包注意事项" tabindex="-1">导入打包注意事项 <a class="header-anchor" href="#导入打包注意事项" aria-label="Permalink to &quot;导入打包注意事项&quot;">​</a></h2><ul><li>插件 zip 中必须且只能有一个 <code>plugin.json</code></li><li><code>plugin.json</code> 可以在 zip 根目录，也可以在某个子目录中</li><li>若 zip 中存在多个 <code>plugin.json</code>，导入会被拒绝</li></ul><p>更多字段说明见下级文档。</p><h2 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h2><ol><li><code>plugins/static</code>：了解固定 URL 来源。</li><li><code>plugins/script</code>：了解脚本入口契约、Runtime API、运行限制与安全边界。</li></ol>`,14)])])}const g=s(l,[["render",o]]);export{h as __pageData,g as default};
